settings.clusterMarkerFunction:
let isAlarm = false;
for(let i=0; i < data.length; i++) {
    if (data[i].isFull === 'true' || data[i].isLowBattery === 'true' || data[i].active === 'false') {
        isAlarm = true;
        break;
    }
}

return isAlarm ? '#fbac36' : '#73c65e';

