let entity, entityName, address, latitude, longitude, lastUpdate, fullLevel, batteryLevel, isFull, fullColor, isLowBattery, lowBatteryColor, isActive, sensorStatus, statusColor, statusBgColor;
if (data.length) {
    entity = data[0];
    entityName = entity.entityName;
    address = entity.address ? entity.address : '-';
    latitude = isNumber(entity.latitude) ? entity.latitude : '-';
    longitude = isNumber(entity.longitude) ? entity.longitude : '-';
    fullLevel = processValue(entity.fullLevel, 0) + '%';
    batteryLevel = processValue(entity.batteryLevel, 0) + '%';
    isFull = entity.isFull && entity.isFull !== 'false';
    fullColor = isFull ? '#D12730' : '#29313C';
    isLowBattery = entity.isLowBattery && entity.isLowBattery !== 'false';
    lowBatteryColor = isLowBattery ? '#D12730' : '#29313C';
    isActive = entity.active === 'true';
    sensorStatus = isActive ? 'Online' : 'Offline';
    statusColor = isActive ? '#3AA94D' : '#C42F37';
    statusBgColor = isActive ? 'rgba(58, 169, 77, 0.08)' : 'rgba(196, 47, 55, 0.08)';
    lastUpdate = (entity['batteryLevel|ts'] || entity['fullLevel|ts']) ? moment(Math.max(entity['batteryLevel|ts'], entity['fullLevel|ts'])).format('D MMM YYYY HH:mm') : '-';
} else {
    entityName = '-';
    address = '-';
    latitude = '-';
    longitude = '-';
    lastUpdate = '-';
    fullLevel = '-';
    batteryLevel = '-';
    isFull = false;
    fullColor = '#29313C';
    isLowBattery = false;
    lowBatteryColor = '#29313C';
    isActive = false;
    sensorStatus = 'Offline';
    statusColor = '#C42F37';
    statusBgColor = 'rgba(196, 47, 55, 0.08)';
}

